// ❌ BAD - logging only on the way in, response time is never captured
app.Use(async (ctx, next) =>
{
    _logger.LogInformation("Request: {Path}", ctx.Request.Path);
    await next();
});

// ✅ GOOD - bidirectional: log request in, log duration out
app.Use(async (ctx, next) =>
{
    var start = DateTime.UtcNow;
    _logger.LogInformation("Inbound: {Path}", ctx.Request.Path);
    await next();
    var elapsed = (DateTime.UtcNow - start).TotalMilliseconds;
    _logger.LogInformation("Outbound: {Path} took {Ms}ms", ctx.Request.Path, elapsed);
});

// ❌ BAD - app.Run placed before other middleware; nothing after it ever runs
app.Run(async ctx => await ctx.Response.WriteAsync("Caught everything"));
app.UseAuthentication(); // dead code - never reached

// ✅ GOOD - app.Map branches the /health path; main pipeline continues for everything else
app.Map("/health", healthApp =>
{
    healthApp.Run(async ctx =>
    {
        ctx.Response.StatusCode = 200;
        await ctx.Response.WriteAsync("Healthy");
    });
});
app.UseAuthentication();
app.MapControllers();

// ❌ BAD - no limits configured; Kestrel exposed edge-facing with defaults only
var builder = WebApplication.CreateBuilder(args);
var app = builder.Build();
app.Run();

// ✅ GOOD - explicit Kestrel limits and HTTPS for edge-facing deployment
var builder = WebApplication.CreateBuilder(args);
builder.WebHost.ConfigureKestrel(options =>
{
    options.Limits.MaxRequestBodySize = 10 * 1024 * 1024; // 10 MB
    options.ListenAnyIP(443, listenOptions =>
        listenOptions.UseHttps());
});
var app = builder.Build();
app.Run();

// ❌ BAD - attempting middleware config before Build(); WebApplication does not exist yet
var builder = WebApplication.CreateBuilder(args);
builder.UseAuthentication(); // compile error - builder has no Use methods

// ✅ GOOD - services before Build(), pipeline after Build()
var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();
builder.Services.AddScoped<IOrderRepository, OrderRepository>();
var app = builder.Build();
app.UseExceptionHandler("/error");
app.UseAuthentication();
app.UseAuthorization();
app.MapControllers();
app.Run();

// ❌ BAD - scoped OrderRepository injected in constructor; becomes a captured singleton
public class AuditMiddleware
{
    private readonly RequestDelegate _next;
    private readonly IOrderRepository _orders; // wrong - captured for app lifetime
    public AuditMiddleware(RequestDelegate next, IOrderRepository orders)
    { _next = next; _orders = orders; }
}

// ✅ GOOD - scoped service in InvokeAsync; resolved fresh per request
public class AuditMiddleware
{
    private readonly RequestDelegate _next;
    public AuditMiddleware(RequestDelegate next) => _next = next;
    public async Task InvokeAsync(HttpContext ctx, IOrderRepository orders)
    {
        await _next(ctx);
        await orders.LogRequestAsync(ctx.Request.Path);
    }
}

// ❌ BAD - Authorization before Authentication; ClaimsPrincipal is empty; all requests get 401
app.UseAuthorization();
app.UseAuthentication();
app.MapControllers();

// ✅ GOOD - correct order wraps exception handling around everything
app.UseExceptionHandler("/error");
app.UseRouting();
app.UseCors("storefront-policy");
app.UseAuthentication();
app.UseAuthorization();
app.MapControllers();

// ❌ BAD - sets 401 status but still calls next(); downstream may overwrite the status
app.Use(async (ctx, next) =>
{
    var key = ctx.Request.Headers["X-Api-Key"].FirstOrDefault();
    if (string.IsNullOrEmpty(key)) { ctx.Response.StatusCode = 401; }
    await next(); // BUG - endpoint still runs and can reset the status to 200
});

// ✅ GOOD - returns early to short-circuit; downstream is protected
app.Use(async (ctx, next) =>
{
    var key = ctx.Request.Headers["X-Api-Key"].FirstOrDefault();
    if (string.IsNullOrEmpty(key) || !IsValidKey(key))
    {
        ctx.Response.StatusCode = 401;
        await ctx.Response.WriteAsync("Invalid or missing API key");
        return; // short-circuit - no next() call
    }
    await next();
});
